INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2389, 218361, 5, 2401, '心网的秘密NNN', '和以住一样，进入“心网”的目的只想给自已15分钟的放松时间，然后重新投入工作中。我习惯于等侍别人问候，今天也不例外~~~~~~~~~尽管在15分钟的时间内没人理我，我下次还是一样选择“等待”，若问我为什么？我还真找不到答案。 
<br>  一样的地点，一样的空间，可以收到不一样的问候，这就是我所想要的，我很坦白的跟对方讲，我只花15分钟的放松时间，听到这句话。理解的人，还会跟我聊。。。不理解的人可能就装哑啦！用固执来形容我好呢！还是。。。。。总之有很多的答案。 
<br>   刚想把一脑子的0------9的阿拉伯数字传输出去，这时碰到比我还N的FELLY，这个时候手拿一杯CAFEW、听着音乐、俩只手在敲打着键盘。看一下，噢！不对呀，今天不是星期六、也不是星期日、是学生也应该在校，是工作者，应该也是在工作，难道是自由职业者~~~~~这时的我忙着要他的电话，也许我可以帮他，15分钟的时间又到啦，今天不能破例。。我要下线啦，电话号码也得到啦！本想等下班后在探个明白，可是我拿起笔就想着~~~不安份的想。。。。我该打个电话，。。。。。', '和以住一样，进入“心网”的目的只想给自已15分钟的放松时间，然后重新投入工作中。我习惯于等侍别人问候，今天也不例外~~~~~~~~~尽管在15分钟的时间内没人理我，我下次还是一样选择“等待”，若问我为什么？我还真找不到答案。

一样的地点，一样的空间，可以收到不一样的问候，这就是我所想要的，我很坦白的跟对方讲，我只花15分钟的放松时间，听到这句话。理解的人，还会跟我聊。。。不理解的人可能就装哑啦！用固执来形容我好呢！还是。。。。。总之有很多的答案。

